B.PP=new A.a1("The aircraft may depart after all checks are completed.","T\xfcm kontroller tamamland\u0131ktan sonra u\xe7ak kalkabilir.","may depart")
B.PK=new A.a1("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.a5b=s([B.OA,B.QN,B.PP,B.PK],t.l)
