B.WX=new A.m(B.x,"Teknik kelime bilgisi neden \xf6nemlidir",'Havac\u0131l\u0131k s\u0131navlar\u0131, kesin teknik terimleri anlama ve kullanma becerinizi \xf6l\xe7er. Bir teknisyenin **aileron** yerine "u\xe7a\u011f\u0131 kald\u0131ran \u015fey" demesi hem profesyonellikten uzak hem de tehlikelidir.\n\nBu ders, u\xe7ak sistemine g\xf6re grupland\u0131r\u0131lm\u0131\u015f en s\u0131k s\u0131nanan bile\u015fenleri kapsar.',null,null,null)
B.ZZ=new A.m(B.v,"\ud83d\udee9\ufe0f U\xe7u\u015f Kontrol Y\xfczeyleri","**Ailerons** \u2014 on the wings; control roll (bank left/right)\n**Elevator** \u2014 on the horizontal stabilizer; controls pitch (nose up/down)\n**Rudder** \u2014 on the vertical stabilizer; controls yaw (nose left/right)\n**Flaps** \u2014 on wing trailing edge; increase lift and drag during takeoff/landing\n**Spoilers** \u2014 on wings; reduce lift, increase drag, assist in roll control",null,null,null)
B.Ze=new A.m(B.v,"\u2699\ufe0f Motor & Yak\u0131t Sistemleri","**Turbine engine** \u2014 compressor \u2192 combustion chamber \u2192 turbine \u2192 nozzle\n**HP fuel shutoff valve** \u2014 high-pressure fuel control valve\n**Fuel manifold** \u2014 distributes fuel to combustion chambers\n**Gearbox** \u2014 transfers power between engine components\n**Nacelle** \u2014 streamlined housing enclosing the engine",null,null,null)
