B.a06=new A.m(B.x,"Neden fonetik alfabe kullan\u0131l\u0131r?",'Havac\u0131l\u0131k telsiz haberle\u015fmesinde benzer seslerin kar\u0131\u015ft\u0131r\u0131lmamas\u0131 kritiktir. "B" ve "D", "M" ve "N" gibi harfler g\xfcr\xfclt\xfcl\xfc bir ortamda kolayca kar\u0131\u015fabilir.\n\nNATO fonetik alfabesi, her harfe \xf6zg\xfcn bir kelime atayarak bu sorunu \xe7\xf6zer. ICAO taraf\u0131ndan standartla\u015ft\u0131r\u0131lm\u0131\u015ft\u0131r ve t\xfcm havac\u0131lar taraf\u0131ndan kullan\u0131l\u0131r.',null,null,null)
