B.XR=new A.m(B.x,"NOTAM nedir?","**NOTAM** (Notice to Air Missions), pilotlar\u0131n haberdar edilmesi gereken havac\u0131l\u0131k bilgilerini i\xe7erir: pist kapan\u0131\u015flar\u0131, VOR ar\u0131zalar\u0131, ge\xe7ici k\u0131s\u0131tlama b\xf6lgeleri ve daha fazlas\u0131.\n\nBu derste ger\xe7ek NOTAM formatlar\u0131n\u0131 \xe7\xf6z\xfcmlemeyi \xf6\u011freneceksin.",null,null,null)
B.ZJ=new A.m(B.v,"NOTAM Format\u0131","**Ba\u015fl\u0131k:** A1234/23 NOTAMN\n**Q sat\u0131r\u0131:** Q) LTBB/QMRLC/IV/NBO/A/000/999/4102N02900E005\n**A:** LTBA (havaliman\u0131 ICAO kodu)\n**B:** 2301010600 (ba\u015flang\u0131\xe7: Ocak 2023, 06:00 UTC)\n**C:** 2301311800 (biti\u015f)\n**E:** \u0130\xe7erik (\u0130ngilizce)\n\n**Yayg\u0131n NOTAM t\xfcrleri:**\n\u2022 QMRLC \u2014 Runway closed\n\u2022 QNVAS \u2014 VOR/NDB ar\u0131zas\u0131\n\u2022 QLCAS \u2014 ILS unserviceable\n\u2022 QRTCA \u2014 Ge\xe7ici k\u0131s\u0131tlama b\xf6lgesi\n\u2022 QFAHW \u2014 Airwork in progress",null,null,null)
B.Q4=new A.a1("E) RWY 06/24 CLSD DUE RESURFACING WIP. EXPECT DUST AND DEBRIS IN VICINITY.","Pist 06/24 y\xfczey yenileme \xe7al\u0131\u015fmas\u0131 nedeniyle kapal\u0131. \xc7evrede toz ve moloz bekleniyor.","CLSD DUE RESURFACING WIP")
B.P3=new A.a1("E) ILS RWY 34L UNSERVICEABLE. CAT I OPS ONLY ON RWY 34R.","Pist 34L ILS hizmete kapal\u0131. Yaln\u0131zca Pist 34R'de CAT I operasyon.","ILS RWY 34L UNSERVICEABLE")
