B.aj5=new A.x(-310,B.M,650,"Which aircraft are affected by this AD?",B.aco,1,B.p,null,null,null)
B.acN=s(["Every 100 flight cycles","Once only","Every 500 flight cycles","At every annual check"],t.s)
