B.UM=new A.m(B.x,"\xc7ocuk yolcularla ileti\u015fim","Bebekli ve \xe7ocuklu yolcular \xf6zel ekipman ve g\xfcvenlik k\u0131lavuzlar\u0131na ihtiya\xe7 duyar. Kabin ekibinin bu ekipmanlara ili\u015fkin terminolojiyi ve kural ifadelerini bilmesi gerekir.",null,null,null)
B.Zb=new A.m(B.v,"Bebek ve \xc7ocuk G\xfcvenlik Terimleri",'**Bassinet** \u2014 u\xe7ak koltu\u011funa monte edilen bebek yata\u011f\u0131 (kalk\u0131\u015f, ini\u015f ve t\xfcrb\xfclansta kald\u0131r\u0131l\u0131r)\n**CARES harness** \u2014 \xe7ocuklar i\xe7in onayl\u0131 emniyet kemeri eki\n**Child restraint system (CRS)** \u2014 \xe7ocuk g\xfcvenlik sistemi (araba koltu\u011fu gibi)\n**Lap infant** \u2014 kucakta ta\u015f\u0131nan bebek (< 2 ya\u015f, kendi koltu\u011fu yok)\n**Supplemental loop belt** \u2014 baz\u0131 \xfclkelerde onayl\u0131 bebek kemeri eki\n\n\u0130fadeler:\n"The bassinet must be removed for takeoff, landing, and during turbulence."\n"Lap infants must be held securely or placed in an approved CRS."\n"Please ensure the child is properly secured in the CARES harness."',null,null,null)
