B.YE=new A.m(B.x,"K\u0131saltmalar neden \xf6nemlidir","Havac\u0131l\u0131k bak\u0131m dok\xfcmanlar\u0131 y\xfczlerce k\u0131saltma i\xe7erir. Bu k\u0131saltmalar\u0131 yanl\u0131\u015f anlamak **ciddi bak\u0131m hatalar\u0131na** yol a\xe7abilir.\n\n\xd6zellikle MEL, SB, AD, NDT ve CMM gibi terimler g\xfcnl\xfck i\u015f ak\u0131\u015f\u0131nda s\u0131k\xe7a kullan\u0131l\u0131r ve do\u011fru anla\u015f\u0131lmalar\u0131 zorunludur.",null,null,null)
B.XD=new A.m(B.v,"\ud83d\udccb Kritik Bak\u0131m K\u0131saltmalar\u0131","**Dok\xfcmanlar:**\n\u2022 AMM \u2014 Aircraft Maintenance Manual\n\u2022 CMM \u2014 Component Maintenance Manual\n\u2022 IPC \u2014 Illustrated Parts Catalog\n\u2022 MEL \u2014 Minimum Equipment List\n\u2022 DDG \u2014 Dispatch Deviation Guide\n\u2022 SB \u2014 Service Bulletin (\xfcretici \xf6nerileri)\n\u2022 AD \u2014 Airworthiness Directive (zorunlu direktif)\n\n**Teknik:**\n\u2022 NDT \u2014 Non-Destructive Testing\n\u2022 LRU \u2014 Line Replaceable Unit\n\u2022 BRT \u2014 Bench Run Test\n\u2022 ENG \u2014 Engine\n\u2022 APU \u2014 Auxiliary Power Unit\n\u2022 HYD \u2014 Hydraulics\n\u2022 BITE \u2014 Built-In Test Equipment\n\n**Durum:**\n\u2022 U/S \u2014 Unserviceable\n\u2022 S/B \u2014 Serviceable\n\u2022 AOG \u2014 Aircraft on Ground (acil durum)",null,null,null)
B.OY=new A.a1("The LRU was found U/S during preflight inspection. An AOG message was sent to maintenance control.","U\xe7u\u015f \xf6ncesi incelemede LRU kullan\u0131lamaz durumda bulundu. Bak\u0131m kontrol\xfcne AOG mesaj\u0131 g\xf6nderildi.","LRU \u2026 U/S \u2026 AOG")
B.ON=new A.a1("Refer to the CMM for detailed overhaul procedures. NDT inspection is required at every major check.","Detayl\u0131 revizyon prosed\xfcrleri i\xe7in CMM'ye bak\u0131n. Her b\xfcy\xfck bak\u0131mda NDT muayenesi gereklidir.","CMM \u2026 NDT")
