B.Vj=new A.m(B.x,"\u0130\u015f emri sistemi neden \xf6\u011frenilmeli","Work Order (WO) ve Job Card (JC/Task Card), bak\u0131m planlamas\u0131 ve takibinin temelini olu\u015fturur. Part-145 onayl\u0131 organizasyonlarda t\xfcm bak\u0131m faaliyetleri bir i\u015f emrine ba\u011fl\u0131d\u0131r.\n\nBir i\u015f emrini do\u011fru okumak: i\u015fin kapsam\u0131n\u0131, kullan\u0131lacak referans dok\xfcmanlar\u0131, gerekli par\xe7a ve ekipman\u0131 ve imza yetkinliklerini anlamay\u0131 gerektirir.",null,null,null)
B.Vq=new A.m(B.v,"\ud83d\udccb \u0130\u015f Emri B\xf6l\xfcmleri ve Terimleri",'**Tipik Work Order b\xf6l\xfcmleri:**\n\u2022 Work scope \u2014 i\u015f kapsam\u0131\n\u2022 Reference documents \u2014 AMM, CMM, SB b\xf6l\xfcmleri\n\u2022 Man-hours \u2014 adam-saat tahmini\n\u2022 Materials required \u2014 gerekli malzeme listesi\n\u2022 Special tools \u2014 \xf6zel alet gereksinimleri\n\u2022 Zone \u2014 u\xe7a\u011f\u0131n \xe7al\u0131\u015fma b\xf6lgesi\n\u2022 Sign-off \u2014 imza/onay\n\n**Job card fiilleri:**\n\u2022 Accomplish \u2014 ger\xe7ekle\u015ftir (formal)\n\u2022 Verify \u2014 do\u011frula\n\u2022 Ensure \u2014 emin ol\n\u2022 Record \u2014 kay\u0131t al\n\u2022 Certify \u2014 onaylay\u0131c\u0131 imzas\u0131 ile onayla\n\n**Onay ifadeleri:**\n\u2022 "Signed and stamped by certifying staff"\n\u2022 "Work completed satisfactorily"\n\u2022 "Complies with [AMM chapter]"',null,null,null)
B.Pr=new A.a1("Task: Accomplish engine oil change in accordance with AMM 12-10-01. Record part numbers and batch numbers of oil used. Sign off upon completion.","G\xf6rev: AMM 12-10-01'e uygun olarak motor ya\u011f\u0131 de\u011fi\u015fimini ger\xe7ekle\u015ftirin. Kullan\u0131lan ya\u011f\u0131n par\xe7a numaralar\u0131n\u0131 ve seri numaralar\u0131n\u0131 kaydedin. Tamamland\u0131\u011f\u0131nda imzalay\u0131n.","Accomplish \u2026 in accordance with \u2026 Sign off upon completion")
