B.Yt=new A.m(B.x,"Servise verme sertifikas\u0131","**Certificate of Release to Service (CRS)**, bir bak\u0131m g\xf6revinin tamamland\u0131ktan sonra yetkili ki\u015fi taraf\u0131ndan imzalanmas\u0131 gereken belgedir. Bu belge olmadan u\xe7ak u\xe7u\u015fa al\u0131namaz.",null,null,null)
